GLOSSARY = {
"Browser":"The user-facing application, privileged services, engine, developer tools, and update system taken together.",
"Engine":"The independent implementation of web parsing, DOM, style, layout, painting, scripting integration, and navigation behavior.",
"Origin":"The scheme, host, and port security principal used by the web platform.",
"Site":"A registrable-domain-oriented isolation grouping; exact policy is versioned because origin and site are not interchangeable.",
"Site instance":"A unit of related documents eligible for a renderer under the current isolation policy.",
"Capability":"An explicit, narrow, revocable authorization to perform an operation or use a resource.",
"Broker":"A privileged process that validates policy before giving a less-trusted process a constrained operation or handle.",
"Renderer":"A sandboxed process that interprets and renders untrusted web content.",
"Display list":"Validated drawing commands produced from layout and paint, consumed by raster and composition stages.",
"Lifecycle state":"A declared tab state such as active, background, frozen, discarded, or restoring.",
"Discard":"Reclaiming a tab process while retaining enough serialized state to restore through navigation or snapshot policy.",
"Browser-owned memory":"Memory attributable to the browser implementation rather than irreducible page content; reports define attribution precisely.",
"Parity":"Evidence-backed coverage of a declared capability inventory, never a blanket assertion.",
"External-dependency gate":"A capability blocked by licensing, commercial approval, platform entitlement, or third-party availability rather than implementation alone.",
"Agent":"An AI-assisted planner operating in an untrusted process through structured observation and action protocols.",
"Observation":"A policy-filtered representation of page or browser state exposed to an agent.",
"Proposal":"A structured action request with preconditions, not authority to execute.",
"Sensitive action":"An operation involving credentials, money, communication, data deletion, downloads, permissions, or cross-origin disclosure.",
"Document version":"A monotonic identity used to reject agent actions planned against stale page state.",
"Taint":"Metadata recording sensitive or origin-bound provenance that constrains data egress.",
"WPT":"Web Platform Tests, the cross-engine conformance suite.",
"Test262":"The ECMAScript conformance suite.",
"FFI":"A foreign-function interface crossing language or ABI boundaries.",
"W^X":"A policy preventing memory from being writable and executable at the same time.",
"Reproducible build":"A build whose declared inputs produce independently verifiable identical outputs.",
"SBOM":"A software bill of materials describing included components.",
"Reference machine":"A versioned hardware, operating-system, power, and configuration target used for performance comparisons.",
"Holdout corpus":"Pages withheld from optimization work to detect benchmark overfitting.",
"Residual risk":"Risk remaining after planned mitigations, explicitly accepted or escalated.",
"Codename":"A temporary project identifier that has not passed trademark and product naming review.",
}
